const __ensureMount = () => {
  let el = document.querySelector('[data-search-results]');
  if (el) return el;
  const main = document.querySelector('main') || document.querySelector('#konten') || document.body;
  el = document.createElement('div');
  el.className = 'search-results';
  el.setAttribute('data-search-results', '');
  main.appendChild(el);
  return el;
};

(function () {
  const utils = window.IKSASS || {};
  const escapeHTML = utils.escapeHtml || ((value) => String(value || ''));
  const normalize = utils.normalizeText || ((value) => String(value || '').toLowerCase());
  const rootPrefix = typeof utils.getRootPrefix === 'function' ? utils.getRootPrefix() : '';

  let index = window.SEARCH_INDEX || [];

  window.addEventListener('search:index:ready', () => {
    index = window.SEARCH_INDEX || [];
    try {
      const input = document.getElementById('search-page-input');
      const q = (input && input.value) ? input.value : (new URLSearchParams(window.location.search).get('q') || '');
      if (document.getElementById('search-results')) {
        window.dispatchEvent(new CustomEvent('search:rerender', { detail: { q } }));
      }
    } catch (_) {}
  });

  function scoreItem(q, item) {
    const qq = normalize(q);
    const title = normalize(item.title);
    const excerpt = normalize(item.excerpt);
    const tags = (item.tags || []).map(normalize).join(' ');
    const category = normalize(item.category);
    let score = 0;
    if (title.includes(qq)) score += 6;
    if (excerpt.includes(qq)) score += 3;
    if (tags.includes(qq)) score += 2;
    if (category.includes(qq)) score += 1;
    if (title.startsWith(qq)) score += 2;
    return score;
  }

  function search(q) {
    const keyword = String(q || '').trim();
    if (!keyword) return [];
    return index
      .map((item) => ({ item, score: scoreItem(keyword, item) }))
      .filter((entry) => entry.score > 0)
      .sort((a, b) => b.score - a.score)
      .map((entry) => entry.item);
  }

  function buildHref(item) {
    return escapeHTML(rootPrefix + (item.url || ''));
  }

  function bindNavbarSuggest() {
    const navInput = document.querySelector('.nav-search-input');
    const suggest = document.querySelector('[data-search-suggest]');
    if (!navInput || !suggest || navInput.dataset.bound === '1') return;

    navInput.dataset.bound = '1';

    const closeSuggest = () => {
      suggest.classList.remove('open');
      suggest.innerHTML = '';
    };

    const openSuggest = () => suggest.classList.add('open');

    function renderSuggest(items) {
      if (!items.length) {
        suggest.innerHTML = '<div class="search-item"><div><p class="t">Tidak ada hasil</p><p class="m">Coba kata kunci lain.</p></div></div>';
        openSuggest();
        return;
      }

      suggest.innerHTML = items.slice(0, 6).map((item) => {
        const descRaw = String(item.excerpt || '').slice(0, 120);
        const badges = [item.category, item.date]
          .filter(Boolean)
          .map((value) => `<span class="search-badge">${escapeHTML(value)}</span>`)
          .join('');

        return `
          <a class="search-item" href="${buildHref(item)}">
            <div>
              <p class="t">${escapeHTML(item.title || '')}</p>
              <p class="m">${escapeHTML(descRaw)}${descRaw.length >= 120 ? '…' : ''}</p>
              <div class="b">${badges}</div>
            </div>
          </a>
        `;
      }).join('');
      openSuggest();
    }

    let debounceId = null;
    navInput.addEventListener('input', () => {
      clearTimeout(debounceId);
      const q = navInput.value.trim();
      if (q.length < 2) {
        closeSuggest();
        return;
      }
      debounceId = setTimeout(() => renderSuggest(search(q)), 120);
    });

    navInput.addEventListener('focus', () => {
      const q = navInput.value.trim();
      if (q.length >= 2) renderSuggest(search(q));
    });

    if (!window.__IKSASS_SEARCH_GLOBALS) {
      window.__IKSASS_SEARCH_GLOBALS = true;
      document.addEventListener('pointerdown', (event) => {
        const wrap = navInput.closest('.nav-search');
        if (wrap && !wrap.contains(event.target)) closeSuggest();
      });
      document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape') closeSuggest();
      });
    }
  }

  function initSearchPage() {
    const pageInput = document.getElementById('search-page-input');
    const pageBtn = document.getElementById('search-page-btn');
    const resultsEl = document.getElementById('search-results');

    function renderResults(q) {
      if (!resultsEl) return;
      const keyword = String(q || '').trim();
      if (!keyword) {
        resultsEl.innerHTML = '';
        return;
      }

      const items = search(keyword);
      if (!items.length) {
        resultsEl.innerHTML = `<div class="search-card"><p class="title">Tidak ada hasil</p><p class="desc">Tidak ditemukan konten untuk kata kunci <b>${escapeHTML(keyword)}</b>.</p></div>`;
        return;
      }

      resultsEl.innerHTML = items.map((item) => {
        const meta = [item.category, item.date].filter(Boolean).join(' • ');
        return `
          <a class="search-card" href="${buildHref(item)}">
            <p class="title">${escapeHTML(item.title || '')}</p>
            ${meta ? `<p class="meta">${escapeHTML(meta)}</p>` : ''}
            ${item.excerpt ? `<p class="desc">${escapeHTML(item.excerpt)}</p>` : ''}
          </a>
        `;
      }).join('');
    }

    if (!window.__IKSASS_SEARCH_RERENDER_BOUND) {
      window.__IKSASS_SEARCH_RERENDER_BOUND = true;
      window.addEventListener('search:rerender', (event) => {
        const q = event && event.detail && typeof event.detail.q === 'string' ? event.detail.q : '';
        renderResults(q);
      });
    }

    try {
      const params = new URLSearchParams(window.location.search);
      const q = params.get('q') || '';
      if (pageInput) {
        pageInput.value = q;
        renderResults(q);
        if (!pageInput.dataset.bound) {
          pageInput.dataset.bound = '1';
          pageInput.addEventListener('keydown', (event) => {
            if (event.key === 'Enter') renderResults(pageInput.value);
          });
        }
      }
      if (pageBtn && pageInput && !pageBtn.dataset.bound) {
        pageBtn.dataset.bound = '1';
        pageBtn.addEventListener('click', () => renderResults(pageInput.value));
      }
    } catch (_) {}
  }

  bindNavbarSuggest();
  document.addEventListener('partials:loaded', bindNavbarSuggest);
  document.addEventListener('DOMContentLoaded', () => {
    bindNavbarSuggest();
    initSearchPage();
  });
})();
